import{_ as s,c as e,a as n,o as i}from"./app-CEcM0piI.js";const p={};function l(d,a){return i(),e("div",null,a[0]||(a[0]=[n(`<h2 id="数据类型相关的关键字" tabindex="-1"><a class="header-anchor" href="#数据类型相关的关键字"><span>数据类型相关的关键字</span></a></h2><p>用于定义变量或类型</p><h3 id="使用方法" tabindex="-1"><a class="header-anchor" href="#使用方法"><span>使用方法</span></a></h3><p>类型 变量名:</p><h3 id="关键字类型" tabindex="-1"><a class="header-anchor" href="#关键字类型"><span>关键字类型</span></a></h3><ol><li><p>char 字符型 占1字节 <code>char ch1=‘1’ 正确 char ch2=‘1234’ 错误 多个字符，不能用单引号</code></p></li><li><p>short 短整型 占2字节 配合int使用 <code>short int a=11;</code> 没有使用signed和unsigned修饰时是默认有符号的，只能使用正整数，负整数，0进行赋值 范围：16位 -32768~32767</p></li><li><p>int 整形 在32位系统下占4字节，16位系统下占2字节 <code>int a=44</code> 默认有符号 范围：32位 -20亿~20亿</p></li><li><p>long 长整型 32位平台下占4字节 <code>long int a=66</code> 范围：32位 -20亿~20亿</p></li><li><p>float 单浮点型 占4字节 范围：7位有效数字，指数-37到38 <code>float b=3.8f;</code> 小数后面要加f修饰，否则会默认为double型</p></li><li><p>double 双浮点型 占8字节 范围：16位有效数字，指数-307到308 精度比单浮点型更高，范围更大 <code>double b=3.8;</code></p></li><li><p>struct 结构体 可以定义结构体类型，也可以定义结构体变量</p></li><li><p>union 联合体（共用体）</p></li><li><p>enum 枚举类型</p></li><li><p>signed 有符号数 用于修饰char、short、int、long <code>signed int a=10; signed int b=-6;</code> 默认情况下signed可以省略</p></li><li><p>unsigned 无符号数 用于修饰char、short、int、long <code>unsigned int a=101; unsigned int b=-101; 错误</code></p></li><li><p>viod 空类型 不能定义变量，一般用来修饰函数的参数或者返回值，代表函数没有参数或返回值 例：</p></li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>void fun(void){}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>代表fun函数没有返回值，也没有参数</p><h2 id="存储相关的关键字" tabindex="-1"><a class="header-anchor" href="#存储相关的关键字"><span>存储相关的关键字</span></a></h2><ol><li>register修饰寄存器变量 在编译的时候告诉编译器这个变量是寄存器变量，尽量 将其存储空间分配在寄存器中 数据只有存储在内存中才有地址编号，用register修饰的变量不能用取地址符对其取地址 不一定在寄存器当中 cpu去寄存器中取数据比去内存中取数据快 不能定义数组，因为寄存器比较宝贵 只能修饰字符型和整形不能修饰浮点型</li></ol><p><code>register chr ch; register short int b; register float d; 错误</code></p><p><code>register int a; int *p; p=&amp;a; 错误，a可能没有地址</code></p><ol start="2"><li><p>static静态 修饰全局变量 局部变量，函数</p></li><li><p>const常量 修饰的变量是只读的，不能修改它的值 <code>const int a=101; </code> 在定义a的时候用const修饰，并赋初值101，在此之后就不能再给a赋值了 a=101; 错误的 可以修饰指针</p></li><li><p>auto自动类型 现在基本不用 auto int a;和int a;是等价的</p></li><li><p>extern外部，用于函数，变量的声明</p></li></ol><h2 id="控制语句相关的关键字" tabindex="-1"><a class="header-anchor" href="#控制语句相关的关键字"><span>控制语句相关的关键字</span></a></h2><ol><li>if</li><li>else</li><li>break</li><li>continue</li><li>for</li><li>while</li><li>do while</li><li>switch case</li><li>go to跳转语句</li><li>default</li></ol><h2 id="其他关键字" tabindex="-1"><a class="header-anchor" href="#其他关键字"><span>其他关键字</span></a></h2><ol><li><p>sizeof测量大小 测量变量数组指针占用存储空间的大小(字节数) <code>int a=10; int num; num=sizeof(a);</code></p></li><li><p>typedef重命名 给一个已有的类型重新起个类型名，并没有创造一个新类型 <code>typedef short int int16; int16 a;和short int a;效果一样</code></p></li><li><p>volatile易改变 告诉cpu每次用volatile变量时，重新去内存中取，保证用的是最新的值，而不是寄存器中的备份 cpu用数据时，先把数据从内存中放到寄存器中然后再使用</p></li></ol><h1 id="基本类型" tabindex="-1"><a class="header-anchor" href="#基本类型"><span>基本类型</span></a></h1><p>常量，程序运行过程中不可改变的量 变量，值可以改变的量</p><h2 id="字符数据" tabindex="-1"><a class="header-anchor" href="#字符数据"><span>字符数据</span></a></h2><h3 id="字符常量" tabindex="-1"><a class="header-anchor" href="#字符常量"><span>字符常量:</span></a></h3><p>直接常量:用单引号括起来的，如&#39;a&#39;，&#39;b&#39;，&#39;0&#39;等 转义字符</p><h3 id="字符变量" tabindex="-1"><a class="header-anchor" href="#字符变量"><span>字符变量</span></a></h3><p>用char定义，以ascii码形式存放在变量的内存单元中</p><p>字符串变量由双引号括起来的字符序列 每个字符串的结尾编译器都会自动添加一个结束标志位<code>\\0</code>，即&quot;a&quot;包含两个字符&#39;a&#39;和<code>\\0</code></p><h2 id="整形数据" tabindex="-1"><a class="header-anchor" href="#整形数据"><span>整形数据</span></a></h2><h3 id="整型常量" tabindex="-1"><a class="header-anchor" href="#整型常量"><span>整型常量：</span></a></h3><p>十进制 八进制 十六进制</p><h3 id="整型变量" tabindex="-1"><a class="header-anchor" href="#整型变量"><span>整型变量</span></a></h3><h2 id="实型数据-浮点型" tabindex="-1"><a class="header-anchor" href="#实型数据-浮点型"><span>实型数据（浮点型）</span></a></h2><h3 id="实型常量" tabindex="-1"><a class="header-anchor" href="#实型常量"><span>实型常量</span></a></h3><p>也称实数或浮点数</p><p>十进制：0.12，5.0 指数形式： 123e3代表<span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mn>123</mn><mo>∗</mo><msup><mn>10</mn><mn>3</mn></msup></mrow><annotation encoding="application/x-tex">123*10^3</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.6444em;"></span><span class="mord">123</span><span class="mspace" style="margin-right:0.2222em;"></span><span class="mbin">∗</span><span class="mspace" style="margin-right:0.2222em;"></span></span><span class="base"><span class="strut" style="height:0.8141em;"></span><span class="mord">1</span><span class="mord"><span class="mord">0</span><span class="msupsub"><span class="vlist-t"><span class="vlist-r"><span class="vlist" style="height:0.8141em;"><span style="top:-3.063em;margin-right:0.05em;"><span class="pstrut" style="height:2.7em;"></span><span class="sizing reset-size6 size3 mtight"><span class="mord mtight">3</span></span></span></span></span></span></span></span></span></span></span> 123e-3代表0.123</p><p>不以f结尾的常量实double类型的，以f结尾的常量是float类型的</p><h1 id="基本类型的数据打印方法" tabindex="-1"><a class="header-anchor" href="#基本类型的数据打印方法"><span>基本类型的数据打印方法</span></a></h1><h2 id="格式化输出字符" tabindex="-1"><a class="header-anchor" href="#格式化输出字符"><span>格式化输出字符:</span></a></h2><p><code>%d </code>十进制有符号整数 <code>%u</code> 十进制无符号整数 <code>%x</code> 以十六进制表示的整数 <code>%o</code> 以八进制表示的整数 <code>%f</code> float 型浮点数 <code>%e</code>指数形式的浮点数 <code>%lf</code> double 型浮点数 <code>%s</code> 字符串 <code>%c</code> 单个字符 <code>%p</code> 指针的值</p><h3 id="特殊应用" tabindex="-1"><a class="header-anchor" href="#特殊应用"><span>特殊应用:</span></a></h3><p><code>%3d</code>:要求宽度为3 位，如果不足 3 位，前面空格补齐:如果足够 3 位，此语句无效 <code>%03d</code>: 要求宽度为3 位，如果不足3 位，前面0 补齐:如果足够3 位，此语句无效 <code>%-3d</code>: 要求宽度为3 位，如果不足 3 位，后面空格补齐;如果足够 3 位，此语句无效 <code>%2f</code>: 小数点后只保留 2 位</p><h1 id="构造类型" tabindex="-1"><a class="header-anchor" href="#构造类型"><span>构造类型</span></a></h1><p>由若干个相同或不同类型数据构成的集合，这种数据类型被称为构造类型 如：数组、结构体、共用体、枚举 例：<code>int a[10];</code></p><h1 id="类型转换" tabindex="-1"><a class="header-anchor" href="#类型转换"><span>类型转换</span></a></h1><p>当表达式中出现了 char 、short int 、int 类型中的一种或者多种，没有其他类型了，参加运算的成员全部变成 int类型的参加运算，结果也是 int 类型的</p><p>当表达式中出现了带小数点的实数，参加运算的成员全部变成 double 类型的参加运算，结果也是 double 型。</p><p>当表达式中有有符号数 也有无符号数，参加运算的成员变成无符号数参加运算结果也是无符号数.(表达式中无实数)</p><p>在赋值语句中等号右边的类型自动转换为等号左边的类型</p><p>注意自动类型转换都是在运算的过程中进行临时性的转换,并不会影响自动类型转换的变量的值和其类型</p><p>无论是强制转换或是自动转换，都只是为了本次运算的需要，而对变量的数据长度进行的临时性转换，而不改变数据定义的类型以及它的值</p><p>![[Pasted image 20230831202609.png]]</p><h1 id="指针" tabindex="-1"><a class="header-anchor" href="#指针"><span>指针</span></a></h1><h1 id="算数运算符" tabindex="-1"><a class="header-anchor" href="#算数运算符"><span>算数运算符</span></a></h1><h2 id="双目运算符" tabindex="-1"><a class="header-anchor" href="#双目运算符"><span>双目运算符</span></a></h2><h2 id="参加运算的操作数有两个" tabindex="-1"><a class="header-anchor" href="#参加运算的操作数有两个"><span>参加运算的操作数有两个 +</span></a></h2><ul><li></li></ul><p>/向下取整 %取余 如果进行除法运算后想要保留后面的小数只能设被除数为float</p><h2 id="单目运算符" tabindex="-1"><a class="header-anchor" href="#单目运算符"><span>单目运算符</span></a></h2><p>参加运算的操作数只有一个</p><p><code>++</code> 自增运算符，给变量值+1 <code>i++ ++i</code></p><p><code>int a=10; a++;</code></p><p><code>--</code> 自减运算符，给变量值-1</p><p><code>j-- --j</code></p><h2 id="三目运算符-条件运算符" tabindex="-1"><a class="header-anchor" href="#三目运算符-条件运算符"><span>三目运算符（条件运算符）</span></a></h2><p>参加运算的操作数有三个 <code>()?():()</code></p><h2 id="优先级" tabindex="-1"><a class="header-anchor" href="#优先级"><span>优先级</span></a></h2><p>先自增（自减）再乘除加减。 ![[IMG_20230901_143848.jpg]]</p><h1 id="关系运算符" tabindex="-1"><a class="header-anchor" href="#关系运算符"><span>关系运算符</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&gt;</span></span>
<span class="line"><span>&lt;</span></span>
<span class="line"><span>==</span></span>
<span class="line"><span>&gt;=</span></span>
<span class="line"><span>&lt;=</span></span>
<span class="line"><span>!=</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="逻辑运算符" tabindex="-1"><a class="header-anchor" href="#逻辑运算符"><span>逻辑运算符</span></a></h1><p>!非 &amp;&amp;与 ||或 ^异或 优先级：高--&gt;低</p><h1 id="原码反码补码" tabindex="-1"><a class="header-anchor" href="#原码反码补码"><span>原码反码补码</span></a></h1><p>最高位为符号位，不参与运算 最高位为0是正数，为1是负数 对于正数，原码反码补码都是一样的 对于负数，负数的原码跟它的绝对值低位一样，最高位为1 负数的反码是除最高位符号位，其他位的数字取反 负数的补码是在它的反码加一</p><h1 id="位运算符" tabindex="-1"><a class="header-anchor" href="#位运算符"><span>位运算符</span></a></h1><p>无论正数还是负数，编译系统都按照内存中存储的内容进行位运算</p><h2 id="位逻辑运算" tabindex="-1"><a class="header-anchor" href="#位逻辑运算"><span>位逻辑运算</span></a></h2><p>将数据的二进制表示形式每一位进行逻辑运算运算</p><h3 id="按位与" tabindex="-1"><a class="header-anchor" href="#按位与"><span><code>&amp;</code>按位与</span></a></h3><h3 id="按位或" tabindex="-1"><a class="header-anchor" href="#按位或"><span><code>|</code>按位或</span></a></h3><h3 id="按位异或" tabindex="-1"><a class="header-anchor" href="#按位异或"><span><code>^</code>按位异或</span></a></h3><h3 id="按位取反" tabindex="-1"><a class="header-anchor" href="#按位取反"><span><code>~</code>按位取反</span></a></h3><p>符号位也取反</p><h2 id="位移运算" tabindex="-1"><a class="header-anchor" href="#位移运算"><span>位移运算</span></a></h2><h3 id="左移" tabindex="-1"><a class="header-anchor" href="#左移"><span><code>&lt;&lt;</code>左移</span></a></h3><p>将数据的二进制形式的所有数向左移一位，溢出舍去空缺补零。</p><h3 id="右移" tabindex="-1"><a class="header-anchor" href="#右移"><span><code>&gt;&gt;</code>右移</span></a></h3><p>分为逻辑右移、算数右移 逻辑右移：高位补0，低位溢出 整数高位补0负数高位补1</p><p>例： <code>0101 1010 &gt;&gt;3</code> 右边三位移出，左边三位补0 结果： 0000 1011</p><p>算数右移：高位补符号位（对无符号数），低位溢出（对有符号数）</p><p>例： <code>1010 1101 &gt;&gt;3</code> 右边三位移出，左边三位补符号位（最高位）1 结果： 1111 0101</p><h3 id="无符号右移" tabindex="-1"><a class="header-anchor" href="#无符号右移"><span><code>&gt;&gt;&gt;</code>无符号右移</span></a></h3><p>无符号右移不区分正负数都是溢出舍去空缺补0</p><h1 id="条件运算符" tabindex="-1"><a class="header-anchor" href="#条件运算符"><span>条件运算符</span></a></h1><p>是唯一的一个三目运算符 <code>()?():()</code></p><p><code>A?B:C</code> 如果A成立，则整个表达式的值为B，如果A不成立，则整个表达式的值为C</p><h1 id="逗号运算符" tabindex="-1"><a class="header-anchor" href="#逗号运算符"><span>逗号运算符</span></a></h1><p><code>(),()</code> 结果是,后边的值 <code>a=(5,6)</code> 结果：a=6</p><p>用于让多个表达式按从左到右顺序依次求值</p><h1 id="自增自减运算符" tabindex="-1"><a class="header-anchor" href="#自增自减运算符"><span>自增自减运算符</span></a></h1><p>++自增运算符 --自减运算符 运算符在变量后面，在当前表达式先用变量的值，下条语句的时候i的值才改变。 运算符在变量前面，先改变变量，再运用到表达式中。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int ×=10；</span></span>
<span class="line"><span>//后++：先用后加</span></span>
<span class="line"><span>//先把x变量中的值拿出来用，赋值给y，然后再进行自增。</span></span>
<span class="line"><span>//赋值给y的值是自增前的。</span></span>
<span class="line"><span>int y=x++;//x=11 y=10</span></span>
<span class="line"><span>//先++：先加后用</span></span>
<span class="line"><span>//先把x进行自增，然后把自增后的结果赋值给左边的变量</span></span>
<span class="line"><span>//先把x自增，变成12，然后再把自增之后的12赋值给z</span></span>
<span class="line"><span>int z=++×;//x=12 z=12</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="运算符的优先级" tabindex="-1"><a class="header-anchor" href="#运算符的优先级"><span>运算符的优先级</span></a></h1><p>![[e678815939c9e527b36e966ccbb2143.jpg]]</p><h1 id="选择控制语句" tabindex="-1"><a class="header-anchor" href="#选择控制语句"><span>选择控制语句</span></a></h1><h2 id="_1、if-else" tabindex="-1"><a class="header-anchor" href="#_1、if-else"><span>1、if……else……</span></a></h2><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>if ()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>else if()//相当于elif</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>else if()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>else</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h2 id="_2、switch-case" tabindex="-1"><a class="header-anchor" href="#_2、switch-case"><span>2、switch……case……</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>switch(表达式)//表达式只能是字符型或整形的（short int   int   long int</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	case 常量表达式1:</span></span>
<span class="line"><span>		语句1;</span></span>
<span class="line"><span>		break;</span></span>
<span class="line"><span>	case 常量表达式2:</span></span>
<span class="line"><span>		语句2;</span></span>
<span class="line"><span>		break;</span></span>
<span class="line"><span>	default:</span></span>
<span class="line"><span>		语句3;</span></span>
<span class="line"><span>		break;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>判断case后面的值是否与switch后面的值相同，若相同则执行case里面的语句，若不相同执行后面的语句。若所有case语句都没有相匹配则执行default里面的的语句。 也可以没有break，但没有break程序执行完符合条件的语句后不会再判断，而是直接执行后面的语句直到遇到break。</p><p><mark>如果在case里面定义了变量就需要把这个case块放到大括号里</mark></p><h1 id="循环控制语句" tabindex="-1"><a class="header-anchor" href="#循环控制语句"><span>循环控制语句</span></a></h1><h2 id="while" tabindex="-1"><a class="header-anchor" href="#while"><span>while……</span></a></h2><h2 id="形式1" tabindex="-1"><a class="header-anchor" href="#形式1"><span>形式1</span></a></h2><p>进入 while 循环的时候，首先会判断条件表达式是否为真，为真进入循环体，否则退出循环</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>while(条件表达式)</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	复合语句</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="形式2-do-while" tabindex="-1"><a class="header-anchor" href="#形式2-do-while"><span>形式2 do……while……</span></a></h2><p>先执行循环体里的代码，然后去判断条件表达式是否为真，为真再次执行循环体，否则退出循环</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>do</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	循环体</span></span>
<span class="line"><span>}while(条件表达式)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="for" tabindex="-1"><a class="header-anchor" href="#for"><span>for……</span></a></h2><p>第一次进入循环的时候执行表达式1，表达式1只使用一次， 表达式2是循环的条件，只有表达式2为真才执行循环体， 每次执行完循环体后，首先执行表达式 3。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>for(表达式1;表达式2;表达式3)</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	复合语句</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="跳转语句" tabindex="-1"><a class="header-anchor" href="#跳转语句"><span>跳转语句</span></a></h1><h2 id="goto" tabindex="-1"><a class="header-anchor" href="#goto"><span>goto</span></a></h2><p>跳转到标签所在的位置，标签可以放在goto语句前面也可以放在goto后面，也可以跳转到其他函数中，标签名随意定义</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>goto tmp;</span></span>
<span class="line"><span>语句1</span></span>
<span class="line"><span>语句2</span></span>
<span class="line"><span>……</span></span>
<span class="line"><span>tmp：//标签</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,123)]))}const h=s(p,[["render",l]]),r=JSON.parse('{"path":"/cpp/c/11/","title":"11 语法","lang":"zh-CN","frontmatter":{"title":"11 语法","createTime":"2025/06/22 10:51:08","permalink":"/cpp/c/11/"},"readingTime":{"minutes":9.65,"words":2895},"git":{"createdTime":1750599657000,"updatedTime":1750644294000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":2,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/C/11 语法.md","headers":[]}');export{h as comp,r as data};
